// POST /api/tenant/google-sync — sync users from Google Workspace via Admin Directory API
// Requires a service-account JSON with domain-wide delegation granted on Google Admin Console
import { NextRequest } from 'next/server'
import { prisma } from '@/lib/prisma'
import { requireAuth, getTenantId, successResponse, errorResponse } from '@/lib/api'
import crypto from 'crypto'

const TA = ['TENANT_ADMIN', 'SUPER_ADMIN']

// Build a signed JWT and exchange it for a Google access token
async function getGoogleAccessToken(serviceAccountJson: string, impersonateEmail: string): Promise<string> {
  const sa = JSON.parse(serviceAccountJson) as {
    client_email: string
    private_key:  string
    [k: string]:  unknown
  }

  const now  = Math.floor(Date.now() / 1000)
  const header  = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url')
  const payload = Buffer.from(JSON.stringify({
    iss:   sa.client_email,
    sub:   impersonateEmail,                                   // domain admin to impersonate
    scope: 'https://www.googleapis.com/auth/admin.directory.user.readonly',
    aud:   'https://oauth2.googleapis.com/token',
    iat:   now,
    exp:   now + 3600,
  })).toString('base64url')

  const sign = crypto.createSign('SHA256')
  sign.update(`${header}.${payload}`)
  const signature = sign.sign(sa.private_key, 'base64url')
  const jwt = `${header}.${payload}.${signature}`

  const res  = await fetch('https://oauth2.googleapis.com/token', {
    method:  'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body:    new URLSearchParams({
      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
      assertion:  jwt,
    }),
  })
  const data = await res.json()
  if (!data.access_token) throw new Error(data.error_description ?? data.error ?? 'Failed to get Google access token')
  return data.access_token as string
}

export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const config = await prisma.adConfig.findUnique({ where: { tenantId } })
  return successResponse({
    configured:     !!(config?.googleServiceAccountJson && config.googleAdminEmail && config.googleDomain),
    lastSyncAt:     config?.lastSyncAt,
    lastSyncStatus: config?.lastSyncStatus,
    lastSyncCount:  config?.lastSyncCount,
  })
}

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const adConfig = await prisma.adConfig.findUnique({ where: { tenantId } })
  if (!adConfig?.googleServiceAccountJson) return errorResponse('Google service account JSON not configured', 400)
  if (!adConfig.googleAdminEmail)          return errorResponse('Google admin email not configured', 400)
  if (!adConfig.googleDomain)             return errorResponse('Google Workspace domain not configured', 400)

  const body        = await req.json().catch(() => ({}))
  const groupRoleMap: Record<string, string> = adConfig.groupRoleMap
    ? JSON.parse(adConfig.groupRoleMap)
    : (body.groupRoleMap ?? {})

  try {
    const token = await getGoogleAccessToken(adConfig.googleServiceAccountJson, adConfig.googleAdminEmail)

    const imported: { email: string; role: string }[] = []
    const errors:   { email: string; error: string }[] = []

    // Page through all users in the domain
    let pageToken: string | undefined
    do {
      const params = new URLSearchParams({
        domain:     adConfig.googleDomain,
        maxResults: '100',
        projection: 'full',
        ...(pageToken ? { pageToken } : {}),
      })
      const res  = await fetch(`https://admin.googleapis.com/admin/directory/v1/users?${params}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error?.message ?? 'Google Directory API error')

      for (const gUser of (data.users ?? []) as any[]) {
        const email = (gUser.primaryEmail as string | undefined ?? '').toLowerCase().trim()
        if (!email) continue
        const name = gUser.name?.fullName ?? gUser.name?.givenName ?? email

        // Google stores org info in customSchemas / organisations / orgUnitPath
        const orgUnit: string = gUser.orgUnitPath ?? ''
        let department: string | undefined = gUser.organizations?.[0]?.department ?? undefined
        let role = 'STUDENT'

        // Map org unit path or department keyword to role
        for (const [keyword, mappedRole] of Object.entries(groupRoleMap)) {
          if (
            orgUnit.toLowerCase().includes(keyword.toLowerCase()) ||
            (department ?? '').toLowerCase().includes(keyword.toLowerCase())
          ) {
            role = mappedRole; break
          }
        }

        try {
          await prisma.user.upsert({
            where:  { email },
            update: {
              name,
              role:       role as any,
              department: department ?? undefined,
              adUpn:      email,
              isSsoUser:  true,
              isActive:   !gUser.suspended,
            },
            create: {
              tenantId,
              email,
              name,
              role:       role as any,
              department: department ?? undefined,
              adUpn:      email,
              isSsoUser:  true,
              isActive:   !gUser.suspended,
            },
          })
          imported.push({ email, role })
        } catch (e: any) {
          errors.push({ email, error: e.message })
        }
      }

      pageToken = data.nextPageToken
    } while (pageToken)

    await prisma.adConfig.update({
      where: { tenantId },
      data: {
        lastSyncAt:     new Date(),
        lastSyncStatus: 'success',
        lastSyncCount:  imported.length,
        provider:       'GOOGLE',
      },
    })

    return successResponse({
      imported:     imported.length,
      errors:       errors.length,
      errorDetails: errors.slice(0, 10),
      sample:       imported.slice(0, 5),
    })
  } catch (err: any) {
    await prisma.adConfig.update({
      where: { tenantId },
      data: { lastSyncStatus: 'error: ' + err.message },
    }).catch(() => {})
    return errorResponse('Google Workspace sync failed: ' + err.message, 500)
  }
}
